VALUES
  ('optometrist-moex-02484', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '眼鏡度數為-4.50DS/-0.50DC×090，轉換成軟式隱形眼鏡時，其度數應為：', '["-4.50 DS", "-4.75 DS", "-5.00 DS", "-4.25 DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02485', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '在許多軟式散光隱形眼鏡設計中，針對動態穩定（dynamic stabilization）設計， 下列敘述何者錯誤？', '["是目前最常使用的設計", "主要是依賴上下眼皮眨眼時的力道", "因無特別加厚區，所以鏡片透氧度沒有減少", "比較容易受地心引力的影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02486', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一個病人屈光矯正的散光軸在170度，使用記號標記在0度和180度的隱形眼鏡試片，戴上試片後 記號顯示正好在170度，處方鏡片之角度應為何？', '["170度", "180度", "10度", "90度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02487', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '後表面光學區曲率半徑（back optic zone radius, BOZR）是配軟式隱形眼鏡的一個重要考慮因素，下 列敘述何者錯誤？', '["BOZR通常是達成適當驗配時最重要的變異因素", "改變BOZR時，厚鏡片比薄鏡片，其滑動改變較明顯", "不同設計之鏡片，BOZR一樣時，其矢深即相同", "BOZR之改變，相對於水膠鏡片，於矽水膠鏡片的影響較明顯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02488', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '病人的角膜弧度為40.50@180/43.50@090，鏡框度數-3.00DS/-3.50DC×180，請問那種隱形眼鏡最適 合這位病人？', '["硬式後散", "硬式前散", "硬式雙散，球面度數效應（spherical power effect）", "硬式雙散，柱面度數效應（cylindrical power effect）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02489', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若硬式隱形鏡片後弧半徑（基弧）維持不變，鏡片直徑減小，鏡片滑動變大，下列敘述何者正確？', '["染色型態（fluorecein patterns）中心帶（central zone）平行", "包覆瞳孔", "矢深變淺", "重量變重"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02490', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關氟矽丙烯酸酯合成物的鏡片材料特色，下列敘述何者錯誤？', '["氧氣可以溶解在氟化物中，故能幫助氧氣通過鏡片材料", "氟可促進淚膜黏液與鏡片的相互作用", "有較低的表面張力，可降低鏡片的乾眼問題", "比矽氧烷丙烯酸酯（silicone/acrylate）製成的鏡片在尺寸上更不穩定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02491', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一位48歲女性，長期配戴月拋型球面軟式水膠隱形眼鏡，最近半年開始左眼視力模糊，戴著隱形眼 鏡的視力為 20/50，拿掉隱形眼鏡的電腦驗光值，左眼為-4.75DS/-1.75DC×020 鏡片矯正視力為 20/50。細隙燈顯微鏡看起來沒有變化，角膜地形圖如下，停戴隱形眼鏡，休息兩周後，矯正視力回 復至 20/20，角膜地形圖中央的不規則散光改善。下列敘述何者最可能？', '["手機使用太多，睫狀肌無法放鬆，導致近視散光增加，休息即可改善", "乾眼症患者比較容易乾燥，使用高含水的鏡片，易在角膜形成上皮破皮", "是圓錐角膜的初期變化，是危險的徵象，須進一步密切追蹤", "長時間戴用隱形眼鏡，導致角膜變形（corneal warpage）所致"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02492', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列那個角膜地形圖與隱形眼鏡配戴時，螢光染色劑在角膜上的分布吻合？', '["高度圖（elevation map）", "切面圖（tangential map）", "矢狀圖（axial map）", "差異圖（difference map）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02493', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜上側上皮弧形損傷（superior epithelium arcuate lesions, SEALs）之敘述，下列何者正確？', '["大部分會造成角膜白斑結疤", "弧形損傷通常靠近瞳孔緣上側與瞳孔緣平行", "使用較厚、彈性較硬之材質的軟式隱形眼鏡，發生的機率可大幅減低", "上側上皮弧形損傷通常發生於單側眼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
